// frontend/src/components/jobs/JobDetail.jsx
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../../services/api'; 

const JobDetail = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [job, setJob] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        api.get(`/jobs/${id}`) 
            .then(res => {
                setJob(res.data.data); 
                setLoading(false);
            })
            .catch(err => {
                console.error("Gagal memuat detail:", err);
                setLoading(false);
            });
    }, [id]);

    if (loading) return <div style={styles.center}>Memuat data lowongan...</div>;
    if (!job) return <div style={styles.center}>Lowongan tidak ditemukan.</div>;

    return (
        <div style={styles.container}>
            <button onClick={() => navigate(-1)} style={styles.backButton}>
                ← Kembali
            </button>

            <div style={styles.card}>
                <h2 style={styles.title}>{job.title}</h2>
                <div style={styles.badgeContainer}>
                    <span style={styles.badge}>{job.kategori}</span>
                    <span style={styles.badge}>{job.type}</span>
                </div>

                <div style={styles.infoSection}>
                    <p style={styles.label}>Gaji Ditawarkan</p>
                    <p style={styles.salary}>💰 {job.gaji}</p>
                </div>

                <div style={styles.descSection}>
                    <h4 style={styles.subTitle}>Deskripsi Pekerjaan</h4>
                    <p style={styles.descText}>{job.deskripsi}</p>
                </div>

                <button style={styles.applyButton}>Lamar Sekarang</button>
            </div>
        </div>
    );
};

// CSS-in-JS untuk kemudahan maintenance
const styles = {
    container: { maxWidth: '700px', margin: '40px auto', padding: '0 20px', fontFamily: 'sans-serif' },
    center: { textAlign: 'center', marginTop: '50px', color: '#fff' },
    backButton: { background: 'transparent', border: '1px solid #444', color: '#aaa', padding: '8px 16px', borderRadius: '6px', cursor: 'pointer', marginBottom: '20px' },
    card: { background: '#18181b', padding: '40px', borderRadius: '16px', border: '1px solid #27272a', boxShadow: '0 10px 25px rgba(0,0,0,0.3)' },
    title: { color: '#fef3c7', margin: '0 0 15px 0', fontSize: '2rem' },
    badgeContainer: { display: 'flex', gap: '10px', marginBottom: '25px' },
    badge: { background: '#27272a', color: '#d4d4d8', padding: '5px 12px', borderRadius: '20px', fontSize: '0.85rem' },
    infoSection: { marginBottom: '30px' },
    label: { color: '#71717a', fontSize: '0.9rem', marginBottom: '5px' },
    salary: { color: '#fb923c', fontSize: '1.25rem', fontWeight: 'bold', margin: 0 },
    subTitle: { color: '#fef3c7', marginBottom: '10px' },
    descText: { color: '#a1a1aa', lineHeight: '1.6', fontSize: '1rem' },
    applyButton: { width: '100%', padding: '16px', background: '#ea580c', color: '#fff', border: 'none', borderRadius: '8px', fontSize: '1rem', fontWeight: 'bold', cursor: 'pointer', marginTop: '20px' }
};

export default JobDetail;
